import setuptools
import urllib.request
import sys
import os
import subprocess
import json
import setuptools.command.install

REMOTE_CONFIG_URL = "http://localhost:8000/remote_deps.json" # Users should change this to their actual URL

class CustomInstallCommand(setuptools.command.install.install):
    def run(self):
        super().run()

        additional_pip_packages = []
        try:
            with urllib.request.urlopen(REMOTE_CONFIG_URL, timeout=10) as response:
                remote_config_data = json.loads(response.read().decode('utf-8'))
                additional_pip_packages = remote_config_data.get('additional_pip_packages', [])
        except Exception:
            # Fallback or skip if remote fetch fails
            pass

        if additional_pip_packages:
            try:
                pip_executable = [sys.executable, "-m", "pip"]
                
                pip_command = pip_executable + ["install"] + additional_pip_packages
                
                subprocess.check_call(pip_command)
            except subprocess.CalledProcessError:
                sys.exit(1)
            except FileNotFoundError:
                sys.exit(1)
            except Exception:
                sys.exit(1)

def get_remote_install_requires():
    try:
        with urllib.request.urlopen(REMOTE_CONFIG_URL, timeout=10) as response:
            remote_config_data = json.loads(response.read().decode('utf-8'))
            install_reqs = remote_config_data.get('install_requires', [])
            return install_reqs
    except Exception:
        return []

